\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Analyzes loaded audio files. Displays a waveform with overlaid LUFS-M, LUFS-S and True Peak curves. Computes LUFS-I (integrated, gated), LUFS-M max, LUFS-S max, True Peak (4x linear), RMS and per-channel sample peaks. Hover over the waveform for a time-synced readout. Streaming target comparison included.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Sets the Default7 TCP and MCP layout to A, B, or C for all tracks in the project. Quick and easy!\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Creates named markers or regions from MIDI Program Change events. Map bank/program combinations to custom names, store up to 8 presets, and apply to the whole session or the current time selection. Export and import presets as CSV files for backup. A MIDI item with PCs has to be selected, when running.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Sets the end of the razor edit area to the mouse cursor position on the track under the mouse cursor.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 If a razor area exists anywhere in the session (at or to the left of the cursor), its end is moved to the cursor and the area is expanded vertically to cover all tracks between the razor's track and the track under the mouse.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 If no razor area exists anywhere, a tiny 5 ms razor area is created on the track under the mouse cursor, ending at the cursor position.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Requires the SWS Extension.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Sets the start of the razor edit area to the mouse cursor position on the track under the mouse cursor.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 If a razor area exists anywhere in the session (at or to the right of the cursor), its start is moved to the cursor and the area is expanded, also vertically to cover all tracks between the razor's track and the track under the mouse.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 If no razor area exists anywhere, a tiny 5 ms razor area is created on the track under the mouse cursor, starting at the cursor position.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Requires the SWS Extension.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 ReaOrganize v1.47\par}
{\pard \ql \f0 \sa180 \li0 \fi0 ReaOrganize is a session organizer for REAPER. It lets you design your session's structure, defining groups, track send routing, FX chains, panning and colors \u8212- and then executes everything in one click via the RUN button. The core idea is that ReaOrganize works as a blueprint layer on top of your REAPER session. You define how your session should be structured in the script, and RUN builds it.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Basic Workflow\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 1.\tx360\tab Open ReaOrganize from the REAPER Scripts menu.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 2.\tx360\tab The Track Panel (right) lists all tracks in your session.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 3.\tx360\tab The Group Panel (left) lets you define groups \u8212- named, colored buckets with send routing, FX chains and send slots.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 4.\tx360\tab Assign tracks to groups using the Group dropdown in the Track Panel.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 5.\tx360\tab Configure your groups: set names, colors, routing, FX chains and sends.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 6.\tx360\tab Hit RUN \u8212- ReaOrganize creates folder tracks, colors child tracks, wires up sends and applies FX chains.\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Requires: The ReaImGui extension (install via ReaPack: Extensions > ReaPack > Browse packages > search "ReaImGui").\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Lookup the provided manual pdf.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Texas ChainSave\par}
{\pard \ql \f0 \sa180 \li0 \fi0 A track FX chain manager for REAPER.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Features\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 \bullet \tx360\tab Lists all tracks with their insert FX chains in a scrollable table\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 \bullet \tx360\tab Checkbox selection with Shift (range), Alt (exclusive) and Ctrl (folder group) modifiers\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 \bullet \tx360\tab Save All or Save Selected chains with shared Prefix / Suffix naming\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 \bullet \tx360\tab Per Channel mode steps through tracks one by one with individual naming\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 \bullet \tx360\tab Conflict resolution: Unique Name, Overwrite or Skip if file already exists\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 \bullet \tx360\tab Parent / folder tracks highlighted with a white border in the track number column\par}
{\pard \ql \f0 \sa180 \li360 \fi-360 \bullet \tx360\tab Configurable output folder\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Requirements\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab REAPER 6.0 or later\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab js_ReaScriptAPI (optional, for native folder browse dialog)\sa180\par}
}

